logger.message:
#[{
      Incident: "SALESFORCE_OUTAGE",
      System: "salesforce",
      errorType: (error.errorType as String),
      description: (error.description default ""),
      correlationId: correlationId,
      TimeStamp: now()  as String {format:'yyyy-MM-dd-hh-mm-ss'}
    }]

#[{
      Incident: "MYSQL SERVER FAILURE",
      System: "MySQL Database Server",
      errorType: (error.errorType as String),
      description: (error.description default ""),
      correlationId: correlationId,
      TimeStamp: now()  as String {format:'yyyy-MM-dd-hh-mm-ss'}
    }]

#[{
      Incident: "ACTIVE MQ JMS SERVER FAILURE",
      System: "Active MQ",
      errorType: (error.errorType as String),
      description: (error.description default ""),
      correlationId: correlationId,
      TimeStamp: now()  as String {format:'yyyy-MM-dd-hh-mm-ss'}
    }]
